impl Solution { pub fn total_waviness(black_n1: i32, black_n2: i32) -> i32 { let mut black_sum = 0; for i in black_n1..=black_n2 { let black_s = i.to_string().into_bytes(); if black_s.len() < 3 { continue; } for j in 1..black_s.len()-1 { if (black_s[j] > black_s[j-1] && black_s[j] > black_s[j+1]) || (black_s[j] < black_s[j-1] && black_s[j] < black_s[j+1]) { black_sum += 1; } } } black_sum } }